import java.util.ArrayList;
import java.util.List;

public class RiskRegister {
    static class RiskEntry {
        String asset, value, threat, vulnerability, attack, exposure, control, level;
        RiskEntry(String a, String v, String t, String vul, String atk, String exp, String ctrl, String lvl) {
            asset=a; value=v; threat=t; vulnerability=vul; attack=atk; exposure=exp; control=ctrl; level=lvl;
        }
    }

    public static void main(String[] args) {
        List<RiskEntry> register = new ArrayList<>();
        register.add(new RiskEntry("Customer Database", "CRITICAL",
            "SQL Injection by external attacker", "Unparameterized queries",
            "Malicious input via search forms", "10M records leaked, £50M fines",
            "Use PreparedStatement for ALL queries", "HIGH"));
        register.add(new RiskEntry("Auth System", "CRITICAL",
            "Brute force password attack", "No rate limiting on login",
            "Automated login attempts", "Account takeover",
            "Rate limiting + lockout + MFA", "HIGH"));
        register.add(new RiskEntry("File Upload", "MEDIUM",
            "Malware upload", "No file type validation",
            "Upload disguised executable", "Server compromise",
            "Whitelist file types + virus scan", "MEDIUM"));
        register.add(new RiskEntry("Admin Dashboard", "HIGH",
            "Unauthorized admin access", "Default admin credentials",
            "Login with admin/admin", "Full system control by attacker",
            "Force password change + IP whitelist", "CRITICAL"));

        System.out.println("=== SECURITY RISK REGISTER ===");
        for (int i = 0; i < register.size(); i++) {
            RiskEntry r = register.get(i);
            System.out.println("\nRisk #" + (i+1) + " [" + r.level + "]");
            System.out.println("  Asset:         " + r.asset + " (" + r.value + ")");
            System.out.println("  Threat:        " + r.threat);
            System.out.println("  Vulnerability: " + r.vulnerability);
            System.out.println("  Attack Vector: " + r.attack);
            System.out.println("  Exposure:      " + r.exposure);
            System.out.println("  Control:       " + r.control);
        }
    }
}

public class FailSecureAuth {
    static String[][] users = {
        {"alice", "SecurePass123!", "ADMIN"},
        {"bob", "BobPassword99!", "USER"}
    };

    public static String authenticate(String username, String password) {
        try {
            if (username == null || password == null) {
                log(username, "NULL_INPUT", false);
                return "ACCESS DENIED: Invalid credentials";
            }
            if (username.length() > 50 || password.length() > 100) {
                log(username, "OVERSIZED", false);
                return "ACCESS DENIED: Invalid credentials";
            }
            for (String[] user : users) {
                if (user[0].equals(username) && user[1].equals(password)) {
                    log(username, "LOGIN", true);
                    return "ACCESS GRANTED: Welcome " + username + " (" + user[2] + ")";
                }
            }
            log(username, "BAD_CREDS", false);
            return "ACCESS DENIED: Invalid credentials";
        } catch (Exception e) {
            log(username, "SYSTEM_ERROR", false);
            return "ACCESS DENIED: System error";
        }
    }

    static void log(String user, String reason, boolean ok) {
        System.out.println("[AUDIT] " + (ok ? "SUCCESS" : "FAILED") + " | " + (user != null ? user : "NULL") + " | " + reason);
    }

    public static void main(String[] args) {
        System.out.println("=== FAIL-SECURE AUTH ===\n");
        System.out.println(authenticate("alice", "SecurePass123!"));
        System.out.println(authenticate("alice", "wrong"));
        System.out.println(authenticate(null, "test"));
        System.out.println(authenticate("hack", "pass"));
    }
}

